static size_t branch_offset(int h,int b){size_t off=0,hw=(size_t)PP_OUT_H*PP_OUT_W;for(int i=0;i<h;i++)for(int j=0;j<6;j++)off+=(size_t)pp_branch_channels(i,j)*hw;for(int j=0;j<b;j++)off+=(size_t)pp_branch_channels(h,j)*hw;return off;}
static const float*dt(const pp_model*m,const char*n,const uint8_t*d){for(uint32_t i=0;i<m->count;i++)if(!std::strcmp(m->records[i].name,n))return reinterpret_cast<const float*>(d+m->records[i].offset);return nullptr;}
static const __half*ht(const pp_model*m,const char*n,const __half*d){for(uint32_t i=0;i<m->count;i++)if(!std::strcmp(m->records[i].name,n))return d+m->records[i].offset/sizeof(float);return nullptr;}
__global__ void pfn(const float*f,int np,const float*w,const float*b,float*out){int id=blockIdx.x*blockDim.x+threadIdx.x;if(id>=np*64)return;int p=id/64,o=id%64;float best=0;for(int j=0;j<20;j++){const float*x=f+((size_t)p*20+j)*11;float v=b[o];for(int k=0;k<11;k++)v+=w[o*11+k]*x[k];best=fmaxf(best,v);}out[(size_t)o*np+p]=best;}
__global__ void scatter(const float*x,const int32_t*c,int np,float*y){int id=blockIdx.x*blockDim.x+threadIdx.x;if(id>=np*64)return;int o=id/np,p=id%np,iy=c[(size_t)p*4+2],ix=c[(size_t)p*4+3];y[((size_t)o*512+iy)*512+ix]=x[(size_t)o*np+p];}
__global__ void f2h(const float*x,__half*y,size_t n){size_t i=(size_t)blockIdx.x*blockDim.x+threadIdx.x;if(i<n)y[i]=__float2half(x[i]);}
__global__ void im2col_linear(const float*x,__half*y,int ci,int hi,int wi,int stride,int kernel,int pad,int npad){int ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1,n=ho*wo,kdim=ci*kernel*kernel;size_t id=(size_t)blockIdx.x*blockDim.x+threadIdx.x,total=(size_t)kdim*npad;if(id>=total)return;int p=id%npad,k=id/npad;if(p>=n){y[id]=__float2half(0);return;}int ox=p%wo,oy=p/wo,ic=k/(kernel*kernel),q=k%(kernel*kernel),iy=oy*stride+q/kernel-pad,ix=ox*stride+q%kernel-pad;float v=0;if((unsigned)iy<(unsigned)hi&&(unsigned)ix<(unsigned)wi)v=x[((size_t)ic*hi+iy)*wi+ix];y[id]=__float2half(v);}
__global__ void im2col_2d(const float*x,__half*y,int hi,int wi,int stride,int kernel,int pad,int n,int npad){int p=blockIdx.x*blockDim.x+threadIdx.x,k=blockIdx.y;if(p>=npad)return;size_t id=(size_t)k*npad+p;if(p>=n){y[id]=__float2half(0);return;}int kk=kernel*kernel,wo=(wi+2*pad-kernel)/stride+1,ox=p%wo,oy=p/wo,ic=k/kk,q=k%kk,iy=oy*stride+q/kernel-pad,ix=ox*stride+q%kernel-pad;float v=0;if((unsigned)iy<(unsigned)hi&&(unsigned)ix<(unsigned)wi)v=x[((size_t)ic*hi+iy)*wi+ix];y[id]=__float2half(v);}
static void launch_im2col(const float*x,__half*y,int ci,int hi,int wi,int stride,int kernel,int pad,int npad){int ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1,n=ho*wo,kdim=ci*kernel*kernel;static int legacy=-1;if(legacy<0)legacy=std::getenv("PP_CUDA_LEGACY_IM2COL")!=nullptr;if(legacy){size_t total=(size_t)kdim*npad;im2col_linear<<<(total+255)/256,256,0,work_stream()>>>(x,y,ci,hi,wi,stride,kernel,pad,npad);}else{dim3 grid((npad+255)/256,kdim);im2col_2d<<<grid,256,0,work_stream()>>>(x,y,hi,wi,stride,kernel,pad,n,npad);}}
__global__ void wmma_conv(const __half*w,const __half*x,float*y,const float*b,int co,int kdim,int n,int npad,int relu){using namespace nvcuda;int mt=blockIdx.y*16,nt=blockIdx.x*16;if(mt>=co||nt>=n)return;wmma::fragment<wmma::matrix_a,16,16,16,__half,wmma::row_major>a;wmma::fragment<wmma::matrix_b,16,16,16,__half,wmma::row_major>v;wmma::fragment<wmma::accumulator,16,16,16,float>c;wmma::fill_fragment(c,0);for(int k=0;k<kdim;k+=16){wmma::load_matrix_sync(a,w+(size_t)mt*kdim+k,kdim);wmma::load_matrix_sync(v,x+(size_t)k*npad+nt,npad);wmma::mma_sync(c,a,v,c);}__shared__ float z[256];wmma::store_matrix_sync(z,c,16,wmma::mem_row_major);__syncthreads();for(int q=threadIdx.x;q<256;q+=32){int r=q/16,s=q%16;if(mt+r<co&&nt+s<n){float t=z[q]+b[mt+r];y[(size_t)(mt+r)*n+nt+s]=relu?fmaxf(t,0):t;}}}
__global__ void wmma_conv_implicit(const __half*w,const float*x,float*y,const float*b,int ci,int co,int hi,int wi,int stride,int kernel,int pad,int relu){using namespace nvcuda;int tid=threadIdx.x,warp=tid>>5,lane=tid&31,mt=blockIdx.y*64+warp*16,nt=blockIdx.x*16,ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1,n=ho*wo,kdim=ci*kernel*kernel;__shared__ __half sv[256],sa[4][256];__shared__ float sz[4][256];wmma::fragment<wmma::matrix_a,16,16,16,__half,wmma::row_major>a;wmma::fragment<wmma::matrix_b,16,16,16,__half,wmma::row_major>v;wmma::fragment<wmma::accumulator,16,16,16,float>c;wmma::fill_fragment(c,0);for(int kb=0;kb<kdim;kb+=16){for(int q=tid;q<256;q+=128){int kr=q>>4,s=q&15,k=kb+kr,p=nt+s,ic=k/(kernel*kernel),tap=k%(kernel*kernel),iy=(p/wo)*stride+tap/kernel-pad,ix=(p%wo)*stride+tap%kernel-pad;float value=0;if(p<n&&(unsigned)iy<(unsigned)hi&&(unsigned)ix<(unsigned)wi)value=x[((size_t)ic*hi+iy)*wi+ix];sv[q]=__float2half(value);}for(int q=tid;q<1024;q+=128){int wm=q>>8,t=q&255,row=blockIdx.y*64+wm*16+(t>>4),k=kb+(t&15);sa[wm][t]=(row<co)?w[(size_t)row*kdim+k]:__float2half(0);}__syncthreads();if(mt<co){wmma::load_matrix_sync(a,sa[warp],16);wmma::load_matrix_sync(v,sv,16);wmma::mma_sync(c,a,v,c);}__syncthreads();}if(mt<co)wmma::store_matrix_sync(sz[warp],c,16,wmma::mem_row_major);__syncthreads();if(mt<co)for(int q=lane;q<256;q+=32){int r=q>>4,s=q&15;if(mt+r<co&&nt+s<n){float t=sz[warp][q]+b[mt+r];y[(size_t)(mt+r)*n+nt+s]=relu?fmaxf(t,0):t;}}}
/* Wider backbone blocks reuse one implicit activation tile across 128 output
 * channels.  The per-warp WMMA work is unchanged; only redundant tile builds
 * and block scheduling are reduced for co=128/256. */
__global__ void wmma_conv_implicit8(const __half*w,const float*x,float*y,const float*b,int ci,int co,int hi,int wi,int stride,int kernel,int pad,int relu){using namespace nvcuda;int tid=threadIdx.x,warp=tid>>5,lane=tid&31,mt=blockIdx.y*128+warp*16,nt=blockIdx.x*16,ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1,n=ho*wo,kdim=ci*kernel*kernel;__shared__ __half sv[256],sa[8][256];__shared__ float sz[8][256];wmma::fragment<wmma::matrix_a,16,16,16,__half,wmma::row_major>a;wmma::fragment<wmma::matrix_b,16,16,16,__half,wmma::row_major>v;wmma::fragment<wmma::accumulator,16,16,16,float>c;wmma::fill_fragment(c,0);for(int kb=0;kb<kdim;kb+=16){int kr=tid>>4,s=tid&15,k=kb+kr,p=nt+s,ic=k/(kernel*kernel),tap=k%(kernel*kernel),iy=(p/wo)*stride+tap/kernel-pad,ix=(p%wo)*stride+tap%kernel-pad;float value=0;if(p<n&&(unsigned)iy<(unsigned)hi&&(unsigned)ix<(unsigned)wi)value=x[((size_t)ic*hi+iy)*wi+ix];sv[tid]=__float2half(value);for(int q=tid;q<2048;q+=256){int wm=q>>8,t=q&255,row=blockIdx.y*128+wm*16+(t>>4),wk=kb+(t&15);sa[wm][t]=(row<co)?w[(size_t)row*kdim+wk]:__float2half(0);}__syncthreads();if(mt<co){wmma::load_matrix_sync(a,sa[warp],16);wmma::load_matrix_sync(v,sv,16);wmma::mma_sync(c,a,v,c);}__syncthreads();}if(mt<co)wmma::store_matrix_sync(sz[warp],c,16,wmma::mem_row_major);__syncthreads();if(mt<co)for(int q=lane;q<256;q+=32){int r=q>>4,s=q&15;if(mt+r<co&&nt+s<n){float t=sz[warp][q]+b[mt+r];y[(size_t)(mt+r)*n+nt+s]=relu?fmaxf(t,0):t;}}}
__global__ void wmma_conv_implicit16(const __half*w,const float*x,float*y,const float*b,int ci,int co,int hi,int wi,int stride,int kernel,int pad,int relu){using namespace nvcuda;int tid=threadIdx.x,warp=tid>>5,lane=tid&31,mt=blockIdx.y*256+warp*16,nt=blockIdx.x*16,ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1,n=ho*wo,kdim=ci*kernel*kernel;__shared__ __half sv[256],sa[16][256];__shared__ float sz[16][256];wmma::fragment<wmma::matrix_a,16,16,16,__half,wmma::row_major>a;wmma::fragment<wmma::matrix_b,16,16,16,__half,wmma::row_major>v;wmma::fragment<wmma::accumulator,16,16,16,float>c;wmma::fill_fragment(c,0);for(int kb=0;kb<kdim;kb+=16){if(tid<256){int kr=tid>>4,s=tid&15,k=kb+kr,p=nt+s,ic=k/(kernel*kernel),tap=k%(kernel*kernel),iy=(p/wo)*stride+tap/kernel-pad,ix=(p%wo)*stride+tap%kernel-pad;float value=0;if(p<n&&(unsigned)iy<(unsigned)hi&&(unsigned)ix<(unsigned)wi)value=x[((size_t)ic*hi+iy)*wi+ix];sv[tid]=__float2half(value);}for(int q=tid;q<4096;q+=512){int wm=q>>8,t=q&255,row=blockIdx.y*256+wm*16+(t>>4),wk=kb+(t&15);sa[wm][t]=(row<co)?w[(size_t)row*kdim+wk]:__float2half(0);}__syncthreads();if(mt<co){wmma::load_matrix_sync(a,sa[warp],16);wmma::load_matrix_sync(v,sv,16);wmma::mma_sync(c,a,v,c);}__syncthreads();}if(mt<co)wmma::store_matrix_sync(sz[warp],c,16,wmma::mem_row_major);__syncthreads();if(mt<co)for(int q=lane;q<256;q+=32){int r=q>>4,s=q&15;if(mt+r<co&&nt+s<n){float t=sz[warp][q]+b[mt+r];y[(size_t)(mt+r)*n+nt+s]=relu?fmaxf(t,0):t;}}}
/* Final heads have at most 12 output channels.  A single-warp block avoids
 * preparing three unused WMMA A/output tiles for the generic 64-channel block. */
__global__ void wmma_conv_implicit_small(const __half*w,const float*x,float*y,const float*b,int ci,int co,int hi,int wi,int stride,int kernel,int pad,int relu){using namespace nvcuda;int lane=threadIdx.x,mt=blockIdx.y*16,nt=blockIdx.x*16,ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1,n=ho*wo,kdim=ci*kernel*kernel;__shared__ __half sv[256],sa[256];__shared__ float sz[256];wmma::fragment<wmma::matrix_a,16,16,16,__half,wmma::row_major>a;wmma::fragment<wmma::matrix_b,16,16,16,__half,wmma::row_major>v;wmma::fragment<wmma::accumulator,16,16,16,float>c;wmma::fill_fragment(c,0);for(int kb=0;kb<kdim;kb+=16){for(int q=lane;q<256;q+=32){int kr=q>>4,s=q&15,k=kb+kr,p=nt+s,ic=k/(kernel*kernel),tap=k%(kernel*kernel),iy=(p/wo)*stride+tap/kernel-pad,ix=(p%wo)*stride+tap%kernel-pad;float value=0;if(p<n&&(unsigned)iy<(unsigned)hi&&(unsigned)ix<(unsigned)wi)value=x[((size_t)ic*hi+iy)*wi+ix];sv[q]=__float2half(value);int row=mt+kr;sa[q]=(row<co)?w[(size_t)row*kdim+kb+s]:__float2half(0);}__syncwarp();wmma::load_matrix_sync(a,sa,16);wmma::load_matrix_sync(v,sv,16);wmma::mma_sync(c,a,v,c);__syncwarp();}wmma::store_matrix_sync(sz,c,16,wmma::mem_row_major);__syncwarp();for(int q=lane;q<256;q+=32){int r=q>>4,s=q&15;if(mt+r<co&&nt+s<n){float t=sz[q]+b[mt+r];y[(size_t)(mt+r)*n+nt+s]=relu?fmaxf(t,0):t;}}}
__device__ float wsum(float v){for(int d=16;d;d>>=1)v+=__shfl_down_sync(0xffffffff,v,d);return v;}
__global__ void direct_conv(const float*x,float*y,const float*w,const float*b,int ci,int co,int hi,int wi,int stride,int kernel,int pad,int relu){int lane=threadIdx.x&31,warp=threadIdx.x>>5,ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1;size_t id=(size_t)blockIdx.x*8+warp,total=(size_t)co*ho*wo;if(id>=total)return;int ox=id%wo,oy=(id/wo)%ho,oc=id/(wo*ho),kk=kernel*kernel;float sum=0;for(int q=lane;q<ci*kk;q+=32){int ic=q/kk,k=q%kk,iy=oy*stride+k/kernel-pad,ix=ox*stride+k%kernel-pad;if((unsigned)iy<(unsigned)hi&&(unsigned)ix<(unsigned)wi)sum+=x[((size_t)ic*hi+iy)*wi+ix]*w[((size_t)oc*ci+ic)*kk+k];}sum=wsum(sum);if(!lane){sum+=b[oc];y[id]=relu?fmaxf(sum,0):sum;}}
__global__ void deconv(const float*x,float*y,const float*w,const float*b,int ci,int co,int hi,int wi,int k){int lane=threadIdx.x&31,warp=threadIdx.x>>5,ho=hi*k,wo=wi*k;size_t id=(size_t)blockIdx.x*8+warp,total=(size_t)co*ho*wo;if(id>=total)return;int ox=id%wo,oy=(id/wo)%ho,oc=id/(wo*ho),ix=ox/k,iy=oy/k,kx=ox%k,ky=oy%k;float s=0;for(int ic=lane;ic<ci;ic+=32)s+=x[((size_t)ic*hi+iy)*wi+ix]*w[((size_t)ic*co+oc)*k*k+ky*k+kx];s=wsum(s);if(!lane)y[id]=fmaxf(s+b[oc],0);}
__constant__ size_t compact_branch_offset[36];
__global__ void compact_candidates(const float*raw,pp_compact_candidate*out,int32_t*counts,int global,int head,int classes,int local,int anchors,float threshold){size_t id=(size_t)blockIdx.x*blockDim.x+threadIdx.x,total=(size_t)anchors*128*128;if(id>=total)return;int a=id/(128*128);uint32_t p=(uint32_t)(id%(128*128));float logit=raw[compact_branch_offset[head*6]+((size_t)a*classes+local)*128*128+p];if(logit<threshold)return;int slot=atomicAdd(counts+global,1);if(slot>=COMPACT_PER_CLASS)return;pp_compact_candidate*c=out+(size_t)global*COMPACT_PER_CLASS+slot;c->logit=logit;c->position=p;c->head=(uint8_t)head;c->anchor=(uint8_t)a;c->class_id=(uint8_t)global;c->reserved=0;int channel=a*10,prefix=0;for(int q=0;q<10;q++,channel++){for(int br=1;br<6;br++){int mul=br==1?4:br==2?2:br==3?6:4,n=classes*mul;if(channel<prefix+n){c->code[q]=raw[compact_branch_offset[head*6+br]+(size_t)(channel-prefix)*128*128+p];break;}prefix+=n;}prefix=0;}}
