static int use_implicit(){static int enabled=-1;if(enabled<0)enabled=std::getenv("PP_CUDA_EXPLICIT")==nullptr;return enabled&&!explicit_heads;}
static int use_implicit_outputs(){static int enabled=-1;if(enabled<0)enabled=std::getenv("PP_CUDA_EXPLICIT_OUTPUTS")==nullptr;return enabled;}
static int use_small_implicit(){static int enabled=-1;if(enabled<0)enabled=std::getenv("PP_CUDA_GENERIC_SMALL")==nullptr;return enabled;}
static int use_warp8_implicit(){static int enabled=-1;if(enabled<0)enabled=std::getenv("PP_CUDA_WARP4")==nullptr;return enabled;}
static int use_warp16_implicit(){static int enabled=-1;if(enabled<0)enabled=std::getenv("PP_CUDA_WARP16")!=nullptr;return enabled;}
static int launch(const pp_model*m,const uint8_t*dw,const __half*dh,const char*name,const float*x,float*y,int ci,int co,int hi,int wi,int stride,int kernel,int pad,int relu,__half*col,int precise,char*e,size_t cap){char nw[48],nb[48];std::snprintf(nw,sizeof nw,"%s.weight",name);std::snprintf(nb,sizeof nb,"%s.bias",name);const float*wt=dt(m,nw,dw),*bias=dt(m,nb,dw);if(!wt||!bias)return fail(e,cap,name);
#ifdef PP_WITH_CUDNN
if(use_cudnn())return pp_cudnn_conv(m,dw,name,x,y,ci,co,hi,wi,stride,kernel,pad,relu,cudnn_precise(precise),work_stream(),e,cap);
#endif
int ho=(hi+2*pad-kernel)/stride+1,wo=(wi+2*pad-kernel)/stride+1,n=ho*wo,kdim=ci*kernel*kernel;if(precise){size_t z=(size_t)co*n;direct_conv<<<(z+7)/8,256,0,work_stream()>>>(x,y,wt,bias,ci,co,hi,wi,stride,kernel,pad,relu);}else{const __half*wh=ht(m,nw,dh);if(!wh)return fail(e,cap,name);if(use_implicit()){if(co<=16&&use_small_implicit()){dim3 grid((n+15)/16,(co+15)/16);wmma_conv_implicit_small<<<grid,32,0,work_stream()>>>(wh,x,y,bias,ci,co,hi,wi,stride,kernel,pad,relu);}else if(co>=256&&use_warp8_implicit()&&use_warp16_implicit()){dim3 grid((n+15)/16,(co+255)/256);wmma_conv_implicit16<<<grid,512,0,work_stream()>>>(wh,x,y,bias,ci,co,hi,wi,stride,kernel,pad,relu);}else if(co>=128&&use_warp8_implicit()){dim3 grid((n+15)/16,(co+127)/128);wmma_conv_implicit8<<<grid,256,0,work_stream()>>>(wh,x,y,bias,ci,co,hi,wi,stride,kernel,pad,relu);}else{dim3 grid((n+15)/16,(co+63)/64);wmma_conv_implicit<<<grid,128,0,work_stream()>>>(wh,x,y,bias,ci,co,hi,wi,stride,kernel,pad,relu);}}else{int npad=(n+15)&~15;launch_im2col(x,col,ci,hi,wi,stride,kernel,pad,npad);dim3 grid((npad+15)/16,(co+15)/16);wmma_conv<<<grid,32,0,work_stream()>>>(wh,col,y,bias,co,kdim,n,npad,relu);}}return 1;}
static int launch_precol(const pp_model*m,const uint8_t*dw,const __half*dh,const char*name,const __half*col,float*y,int co,int relu,char*e,size_t cap){char nw[64],nb[64];std::snprintf(nw,sizeof nw,"%s.weight",name);std::snprintf(nb,sizeof nb,"%s.bias",name);const __half*wh=ht(m,nw,dh);const float*bias=dt(m,nb,dw);if(!wh||!bias)return fail(e,cap,name);constexpr int n=128*128,kdim=64*9;dim3 grid(n/16,(co+15)/16);wmma_conv<<<grid,32,0,work_stream()>>>(wh,col,y,bias,co,kdim,n,n,relu);return 1;}
