extern "C" int pp_infer_cuda(const pp_model*m,const pp_pillars*p,pp_raw_output*out,pp_profile*pr,char*e,size_t cap){return infer_cuda_impl(m,p,out,nullptr,0,0,pr,e,cap);}
extern "C" int pp_infer_cuda_detect(const pp_model*m,const pp_pillars*p,pp_detections*d,float score,float nms,pp_profile*pr,char*e,size_t cap){return infer_cuda_impl(m,p,nullptr,d,score,nms,pr,e,cap);}
